// 面板高度
function setRightPanelHeight(id) {

    function heightFun() {

        var wh = $(window).height();
        var panelHei = wh - 125,

            changemodalSscroll = panelHei + 20,

            scrollHei = panelHei - 196,

            panleScroll = panelHei - 74,

            animatScroll = panelHei - 258;

        settingNavItem = panelHei - 40,

            $(id).css('height', panelHei);

        //$(id).find('.dynamic-scroll').css('height',scrollHei);

        $(id).find('.panel-scroll').css('height', panleScroll);

        $(id).find('.animation-scroll').css('height', animatScroll);

        $(id).find('.changemodal-scroll').css('height', changemodalSscroll);

        $(id).find('.nav-item-box').css('minHeight', settingNavItem);

        $(id).find(".m-editHeight").height(wh - 122);
    }

    heightFun();

    $(window).resize(function () {
        heightFun();
    });
    $(id).find(".f-scrollbar").lzscroll({ mode: 'hover', useMutation: false });
}

// 面板锁定即解锁
function titleUnlock($, id, a, b) {

    $(id).find('.panel-title-icon').off('click.lz-unlock').on('click.lz-unlock', function () {

        var $this = $(this),

            icon = $this.find('.icon')

        if (icon.hasClass('icon-pin')) {

            icon.removeClass('icon-pin').addClass('icon-pin-lock');

            $this.addClass('current');

            $this.data('lztitle', a);

        } else {

            icon.removeClass('icon-pin-lock').addClass('icon-pin');

            $this.removeClass('current');

            $this.data('lztitle', b);
        }
    });
}

