// input选中样式
function inputCurrent($, id) {

    // console.log($('.u-designer-panel'));

    $(id).find('.u-lzdesigner-panel').find('.form-control').on('focus.lz-focus', function () {

        $(this).closest('.form-group').addClass('current');

    }).on('blur.lz-blur', function () {

        $(this).closest('.form-group').removeClass('current');

    })
}

