// 字体图标开启关闭
function fontIcon($, id) {

    $(id).find('.tip-normal').find('.m-switch').off('click.lz-switch').on('click.lz-switch', function () {

        if ($(this).hasClass('checked')) {

            $(id).find('.setfont-change-icon').addClass('open');

        } else {

            $(id).find('.setfont-change-icon').removeClass('open');
        }
    });
}

// 边框线型切换
function borderCurrent($, id) {

    var $box = $(id + ' .set-border-style').find('.square-box');

    $box.off('click.lz-border').on('click.lz-border', function () {

        $box.removeClass('current');

        $(this).addClass('current');

        if ($(this).find('.icon').hasClass('icon-line_none')) {

            $(id).find('.border-line,.border-core').removeClass('current')
        }

    });

}

// 边框线型效果图交互
function borderBoxCurrent($, id) {

    var $parent = $(id + ' .border-square'),

        $line = $parent.find('.line-click'),

        $box = $parent.find('.border-core');

    $line.off('click').on('click', function () {

        $line.removeClass('current');

        $box.removeClass('current');

        $('#style_tip-normal').find('.icon-line_none').closest('.square-box').removeClass('current');

        $(this).addClass('current');

    });

    $box.off('click').on('click', function () {

        $(this).addClass('current');

        $line.addClass('current');

        $(id).find('.icon-line_none').closest('.square-box').removeClass('current');

    });

}

// 动画类型切换
function animatSwitch($, id) {

    $(id).find('.animat-thumbnail-itme').off('click').on('click', function () {

        $(id).find('.animat-thumbnail-itme').removeClass('current');

        $(this).addClass('current')
    })
}

// 动画效果切换单选效果
function animatRadio($, radioSelect) {
    var checked;

    $(radioSelect).find('.m-radio-switch').each(function (index, el) {
        $input = $(el).find('input');
        checked = $input.prop('checked');
        checked && $(el).addClass('current')
    });

    $(radioSelect).find('.radio-switch').off('click.lz-radio').on('click.lz-radio', function () {
        $(radioSelect).find('.m-radio-switch').removeClass('current')
        $(this).closest('.m-radio-switch').addClass('current');
    });
}


// 位置偏移量选择
function locationOffset($, id) {

    $(id).find('.u-location-square').off('click.lz-offset').on('click.lz-offset', '.click-square', function () {

        $(id).find('.u-location-square').find('.click-square').removeClass('current');

        $(this).addClass('current')
    })
}

// 统一的自定义关闭方法
function sideWinClose(id) {

    $(id).find('.icon-close-blockInfo').off('click').on('click', function () {
        $(id).hide();
    })
}




